from haystack import Pipeline
from haystack.components.builders import PipelineSchema

 def detect_type_mismatches(pipeline: Pipeline):
    schema = PipelineSchema.from_pipeline(pipeline)
    mismatches = []
    for connection in schema.connections:
        output_type = connection.from_node.outputs[connection.from_key].type
        input_type = connection.to_node.inputs[connection.to_key].type
        if output_type != input_type:
            mismatches.append({
                'connection': f'{connection.from_node.name}.{connection.from_key} -> {connection.to_node.name}.{connection.to_key}',
                'expected': input_type,
                'received': output_type
            })
    return mismatches

# Usage
pipe = Pipeline()
issues = detect_type_mismatches(pipe)
if issues:
    print('Type mismatches found:', issues)

from haystack.dataclasses import Document
from typing import List, Dict, Any

 def check_agent_consistency(outputs: List[Dict[str, Any]]) -> Dict[str, bool]:
    if not outputs:
        return {'consistent': True}

    first_output = outputs[0]
    for i, output in enumerate(outputs[1:], 1):
        if set(first_output.keys()) != set(output.keys()):
            return {
                'consistent': False,
                'mismatch_indices': [0, i],
                'first_keys': list(first_output.keys()),
                'output_keys': list(output.keys())
            }
    return {'consistent': True}

