if not consistency['consistent']:
    print('Agent output inconsistency:', consistency)

from haystack import Pipeline
from functools import wraps

 def monitor_silent_failures(component):
    original_run = component.run

    @wraps(original_run)
    def wrapped_run(*args, **kwargs):
        result = original_run(*args, **kwargs)
        empty_outputs = []
        for key, value in result.items():
            if value is None or (isinstance(value, list) and not value):
                empty_outputs.append(key)
        if empty_outputs:
            print(f'WARNING: {component.__class__.__name__} produced empty outputs: {empty_outputs}')
        return result
    component.run = wrapped_run
    return component

# Usage
retriever = monitor_silent_failures(retriever)
generator = monitor_silent_failures(generator)
pipe.add_components([retriever, generator])
